import type { Part } from '@sketchflat/svg-schema';

// 데모용 — 라이브러리 에셋 클릭 시 fit-to-bbox 경로를 우회해 미리 측정해 둔 part 데이터를
// 그대로 캔버스에 떨어뜨린다. 위치 / 스케일 / 패스 굵기 / 모양까지 1:1 보존되므로
// 영상 시연에서 "에셋이 척척 맞는다" 를 자연스럽게 보여줄 수 있다.
//
// 키는 library_assets 테이블의 id (= 카탈로그 ID).
// 값은 z_index 오름차순 part 배열. id / group_id / z_index 는 inject 시점에 재배정된다.
// transform 은 identity (anchor 좌표가 world 기준), stroke_width / stroke_dasharray 도
// 캡처 당시 transform.scale 로 미리 곱해서 저장한다. Konva Path 는 strokeScaleEnabled
// 가 기본 true 라 transform.scaleX 가 stroke 두께에 곱해지므로, anchor 만 baking 하고
// stroke 를 그대로 두면 캔버스 두께가 1/scale 배 두꺼워진다 (예: 캡처 scale=0.146 +
// stroke=2 → baking 후 6.7x 두꺼워지는 회귀). bakeStrokeIntoIdentity 가 dump/apply
// 양쪽에서 동일 baking 을 수행한다.
//
// 카테고리 별칭 — 라이브러리 카탈로그는 영문 카테고리("Collar"/"Sleeve"…) 를 쓰지만, 과거에
// 한글 카테고리로 자동 생성된 레이어 그룹("카라"·"카라 (둥근 카라)" 등) 도 함께 잡아서 숨겨야
// 데모 프로젝트가 깨지지 않는다. value 들은 모두 그룹명으로 노출될 수 있는 이전 표기.
// applyLibraryAssetToCanvas 의 스냅샷 분기가 카테고리·별칭에 정확히 일치하거나 `${alias} (`
// 로 시작하는 최상위 그룹의 파트를 모두 visible=false 처리한다.
export const LIBRARY_ASSET_CATEGORY_ALIASES: Record<string, string[]> = {
  Collar: ['카라'],
  Sleeve: ['소매', 'Sleeve (Left)', 'Sleeve (Right)'],
  Body: ['몸판'],
  Placket: ['플라켓'],
  Pocket: ['포켓'],
  Button: ['단추'],
  Cuff: ['커프스'],
  Hem: ['밑단'],
};

